import{_ as o,r as d,o as i,c as l,b as e,e as s,w as c,d as a,f as r}from"./app-55c326ac.js";const t={},p=e("h1",{id:"_14-使用网络",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_14-使用网络","aria-hidden":"true"},"#"),a(" 14. 使用网络")],-1),u={class:"table-of-contents"},v=r(`<p>Docker允许通过外部访问容器或容器互联的方式来提供网络服务</p><h2 id="外部访问容器" tabindex="-1"><a class="header-anchor" href="#外部访问容器" aria-hidden="true">#</a> 外部访问容器</h2><p>容器中运行一些网络应用，可以通过<code>-P</code>或<code>-p</code>参数指定端口映射。<br> 当使用<code>-P</code>时，Docker会随机映射一个<code>49000~49900</code>的端口到内容容器开放的网络端口<br> 使用<code>docker container ls</code>，可以查看本地端口49155倍映射到容器的5000端口。<strong>此时访问本机的<code>49155</code>端口即可访问容器内web应用提供的界面</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-P</span> training/webapp python app.py
<span class="token function">docker</span> container <span class="token function">ls</span> <span class="token parameter variable">-l</span>

<span class="token comment"># 也可以通过docker logs命令查看应用信息</span>
<span class="token function">docker</span> logs <span class="token parameter variable">-f</span> nostalgic_morse
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>-p</code>则可以指定要映射的端口，并且，在一个指定端口上只可以绑定一个容器，支持的格式有：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>ip:hostPort:containerPort | ip::containerPort | hostPort:containerPort
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="映射所有接口地址" tabindex="-1"><a class="header-anchor" href="#映射所有接口地址" aria-hidden="true">#</a> 映射所有接口地址</h3><p>使用<code>hostPort:containerPort</code>格式 本地的5000端口映射到容器的5000端口。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-p</span> <span class="token number">5000</span>:5000 training/webapp python app.py

<span class="token comment"># 此时默认会绑定本地所有接口上的所有地址</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="映射到指定地址的指定端口" tabindex="-1"><a class="header-anchor" href="#映射到指定地址的指定端口" aria-hidden="true">#</a> 映射到指定地址的指定端口</h3><p>可以使用<code>ip:hostPort:containerPort</code>格式指定映射使用一个特定地址，比如localhost地址127.0.0.1</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-p</span> <span class="token number">127.0</span>.0.1:5000:5000 training/webapp python app.py
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="映射到指定地址的任意端口" tabindex="-1"><a class="header-anchor" href="#映射到指定地址的任意端口" aria-hidden="true">#</a> 映射到指定地址的任意端口</h3><p>使用<code>ip::containerPort</code>绑定localhost的任意端口到容器的5000端口，本地主机会自动分配一个端口。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-p</span> <span class="token number">127.0</span>.0.1::5000 training/webapp python app.py

<span class="token comment"># 还可以使用 udp 标记来指定 udp 端口</span>
<span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-p</span> <span class="token number">127.0</span>.0.1::5000/udp training/webapp python.py

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="查看映射端口配置" tabindex="-1"><a class="header-anchor" href="#查看映射端口配置" aria-hidden="true">#</a> 查看映射端口配置</h3><p>使用<code>docker port</code>来查看当前映射的端口配置，也可以查看绑定的地址。。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> port nostalgic_morse <span class="token number">5000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>注意：</strong></p><ul><li>容器有自己的内部网络和IP地址(使用<code>docker inspect</code>可以获取所有的变量，Docker还可以有一个可变的网络配置)</li><li><code>-p</code>标记可以多次使用来绑定多个端口</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-d</span> <span class="token parameter variable">-p</span> <span class="token number">5000</span>:5000 <span class="token parameter variable">-p</span> <span class="token number">3000</span>:80 training/webapp python app.py

<span class="token comment"># -p标记绑定多个端口</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="容器互联" tabindex="-1"><a class="header-anchor" href="#容器互联" aria-hidden="true">#</a> 容器互联</h2><p>可以使用<code>--link</code>参数来使容器互联<br> 随着Docker网络的完善，建议将容器加入自定义的Docker网络来连接多个容器，而不是使用<code>--link</code></p><h3 id="新建网络" tabindex="-1"><a class="header-anchor" href="#新建网络" aria-hidden="true">#</a> 新建网络</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> network create <span class="token parameter variable">-d</span> brigde my-net

<span class="token comment"># -d 参数指定Docker网路类型；有 bridge(桥接网络)，overlay。其中 overlay 网络类型用于 Swarm mode</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="连接容器" tabindex="-1"><a class="header-anchor" href="#连接容器" aria-hidden="true">#</a> 连接容器</h3><p>运行一个容器并连接到新建的my-net网络</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-it</span> <span class="token parameter variable">--rm</span> <span class="token parameter variable">--name</span> busybox1 <span class="token parameter variable">--network</span> my-net busybox <span class="token function">sh</span>
<span class="token comment"># -it 显示命令行并进入中断</span>
<span class="token comment"># --rm    退出时删除操作</span>
<span class="token comment"># --name  容器的名字</span>
<span class="token comment"># busybox 镜像</span>
<span class="token comment"># --network 连接的网络</span>
<span class="token comment"># sh    运行sh命令</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>打开新的终端，在运行一个容器并加入到my-net网络</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-it</span> <span class="token parameter variable">--rm</span> <span class="token parameter variable">--name</span> busybox2 <span class="token parameter variable">--network</span> my-net busybox <span class="token function">sh</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在打开一个新的终端查看容器信息</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> container <span class="token function">ls</span> <span class="token parameter variable">-a</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>测试</strong> 用ping来证明busybox1容器和busybox2容器建立互联关系</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在busybox1容器输入下列命令  </span>
<span class="token function">ping</span> busybox2           <span class="token comment"># 会将busybox2解析成IP</span>

<span class="token comment"># 在busybox2容器输入下列命令</span>
<span class="token function">ping</span> busybox1           <span class="token comment"># 会将busybox1解析成IP</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="配置dns" tabindex="-1"><a class="header-anchor" href="#配置dns" aria-hidden="true">#</a> 配置DNS</h2><p>自定义配置容器的主机名和DNS，就是Docker利用虚拟文件来挂载容器的3个相关配置文件 在容器中使用<code>mount</code>命令可以看到挂载信息</p><p>这可以让宿主主机的DNS信息发生更新后，所有的Docker容器的DNS配置 通过<code>/etc/resolv.conf</code>文件得到更新</p><p>配置全部容器的DNS，也可以在<code>/etc/docker/daemon.json</code>文件中增加下面的内容来设置：</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
    <span class="token property">&quot;dns&quot;</span> <span class="token operator">:</span> <span class="token punctuation">[</span>
      <span class="token string">&quot;114.114.114.114&quot;</span><span class="token punctuation">,</span>
      <span class="token string">&quot;8.8.8.8&quot;</span>
    <span class="token punctuation">]</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样配置后，每次启动的容器DNS自动配置为<code>114.114.114.114</code>和<code>8.8.8.8</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">docker</span> run <span class="token parameter variable">-it</span> <span class="token parameter variable">--rm</span> centos:7 <span class="token function">cat</span>  /etc/resolv.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果用户想要手动指定容器的配置，可以在使用<code>docker run</code>命令启动容器时加入如下参数：</p><p><code>-h HOSTNAME</code>或者<code>--hostname=HOSTNAME</code> 设定容器的主机名，它会被写到容器内的<code>/etc/hostname</code>和 <code>/etc/hosts</code>。但它在容器外部看不到，既不会在<code>docker container ls</code> 中显示，也不会在其他的容器的<code>/etc/hosts</code>看到。</p><p><code>--dns=IP_ADDRESS</code> 添加 DNS 服务器到容器的<code>/etc/resolv.conf</code> 中，让容器用这个服务器来解析所有不在<code>/etc/hosts</code>中的主机名。</p><p><code>--dns-search=DOMAIN</code> 设定容器的搜索域，当设定搜索域为 <code>.example.com</code> 时，在搜索一个名为 <code>hos</code>t 的主机时，DNS 不仅搜索 <code>host</code>，还会搜索 <code>host.example.com</code>。</p><blockquote><p>注意：如果在容器启动时没有指定最后两个参数，<code>Docker</code> 会默认用主机上的 <code>/etc/resolv.conf</code> 来配置容器。</p></blockquote>`,47);function b(m,h){const n=d("router-link");return i(),l("div",null,[p,e("nav",u,[e("ul",null,[e("li",null,[s(n,{to:"#外部访问容器"},{default:c(()=>[a("外部访问容器")]),_:1}),e("ul",null,[e("li",null,[s(n,{to:"#映射所有接口地址"},{default:c(()=>[a("映射所有接口地址")]),_:1})]),e("li",null,[s(n,{to:"#映射到指定地址的指定端口"},{default:c(()=>[a("映射到指定地址的指定端口")]),_:1})]),e("li",null,[s(n,{to:"#映射到指定地址的任意端口"},{default:c(()=>[a("映射到指定地址的任意端口")]),_:1})]),e("li",null,[s(n,{to:"#查看映射端口配置"},{default:c(()=>[a("查看映射端口配置")]),_:1})])])]),e("li",null,[s(n,{to:"#容器互联"},{default:c(()=>[a("容器互联")]),_:1}),e("ul",null,[e("li",null,[s(n,{to:"#新建网络"},{default:c(()=>[a("新建网络")]),_:1})]),e("li",null,[s(n,{to:"#连接容器"},{default:c(()=>[a("连接容器")]),_:1})])])]),e("li",null,[s(n,{to:"#配置dns"},{default:c(()=>[a("配置DNS")]),_:1})])])]),v])}const g=o(t,[["render",b],["__file","Docker系列学习-14.使用网络.html.vue"]]);export{g as default};
